func rustTypeToGo(rustType string) string {
    rustType = trimPointerType(rustType)
    if goType, ok := rustToGoTypes[rustType]; ok {
        return goType
    }
    if strings.HasPrefix(rustType, "P") {
        return "uintptr"
    }
    return "uintptr"
}

func trimPointerType(t string) string {
    t = strings.TrimSpace(t)
    for strings.HasPrefix(t, "*mut ") || strings.HasPrefix(t, "*const ") {
        if strings.HasPrefix(t, "*mut ") {
            t = strings.TrimPrefix(t, "*mut ")
        } else {
            t = strings.TrimPrefix(t, "*const ")
        }
    }
    return t
}

