func GetHookInfo(name string) *HookInfo {
    for i := range HookDatabase {
        if HookDatabase[i].Name == name {
            return &HookDatabase[i]
        }
    }
    return nil
}

func (p *Packet) InstallHook(apiName string, hookType HookType, processId uint32, hookHandler uint64) (*HookResponse, error) {
    req := HookRequest{
        Action:      "install_hook",
        HookType:    hookType,
        ApiName:     apiName,
        ProcessId:   processId,
        HookHandler: hookHandler,
    }
    data, _ := json.Marshal(req)
    resp := SendReceive[HookResponse](p, data)
    if resp == nil || !resp.Success {
        return nil, fmt.Errorf("install hook failed: %s", resp.Message)
    }
    return resp, nil
}

func (p *Packet) RemoveHook(apiName string, hookType HookType) error {
    req := HookRequest{
        Action:   "remove_hook",
        HookType: hookType,
        ApiName:  apiName,
    }
    data, _ := json.Marshal(req)
    resp := SendReceive[HookResponse](p, data)
    if resp == nil || !resp.Success {
        return fmt.Errorf("remove hook failed: %s", resp.Message)
    }
    return nil
}

func (p *Packet) ListHooks() []HookInfo {
    return HookDatabase
}

// HookCallContext provides context for hook callback
type HookCallContext struct {
    ApiName    string
    ProcessId  uint32
    ThreadId   uint32
    Registers  map[string]uint64
    StackPtr   uint64
    RetAddr    uint64
}

// HookCallback is called when a hooked API is invoked
type HookCallback func(ctx *HookCallContext) error

// HookManager manages hook registration and callbacks
type HookManager struct {
    hooks     map[string]*HookEntry
    callbacks map[string]HookCallback
}

type HookEntry struct {
    Info       *HookInfo
    Type       HookType
    ProcessId  uint32
    Handler    uint64
    Callback   HookCallback
    Enabled    bool
}

func NewHookManager() *HookManager {
    return &HookManager{
        hooks:     make(map[string]*HookEntry),
        callbacks: make(map[string]HookCallback),
    }
}

func (m *HookManager) Register(apiName string, hookType HookType, processId uint32, callback HookCallback) error {
    info := GetHookInfo(apiName)
    if info == nil {
        return fmt.Errorf("unknown API: %s", apiName)
    }
    m.hooks[apiName] = &HookEntry{
        Info:      info,
        Type:      hookType,
        ProcessId: processId,
        Callback:  callback,
        Enabled:   true,
    }
    return nil
}

func (m *HookManager) Unregister(apiName string) {
    delete(m.hooks, apiName)
    delete(m.callbacks, apiName)
}

func (m *HookManager) GetHook(apiName string) *HookEntry {
    return m.hooks[apiName]
}

func (m *HookManager) ListActiveHooks() []string {
    var result []string
    for name, entry := range m.hooks {
        if entry.Enabled {
            result = append(result, name)
        }
    }
    return result
}
